class Solution:
    def maxDiff(self, num):
        s = str(num)
        # maximize: replace first non-9 with 9
        best = s
        for ch in s:
            if ch != '9':
                best = s.replace(ch, '9')
                break
        # minimize: no leading zeros, no zero result
        worst = s
        if s[0] != '1':
            worst = s.replace(s[0], '1')
        else:
            for ch in s[1:]:
                if ch not in ('0', '1'):
                    worst = s.replace(ch, '0')
                    break
        return int(best) - int(worst)

