var maxDiff = function(num) {
    const s = String(num);
    // maximize: replace first non-9 digit with 9
    let a = s;
    for (const ch of s) {
        if (ch !== '9') { a = s.split(ch).join('9'); break; }
    }
    // minimize: avoid leading zeros
    let b = s;
    if (s[0] !== '1') {
        b = s.split(s[0]).join('1');
    } else {
        for (let i = 1; i < s.length; i++) {
            if (s[i] !== '0' && s[i] !== '1') {
                b = s.split(s[i]).join('0');
                break;
            }
        }
    }
    return parseInt(a) - parseInt(b);
};
